noncompliant:
char* ptr = malloc(100);
free(ptr);
strcpy(ptr, "data");  // Noncompliant: using freed memory

int* arr = malloc(sizeof(int) * 10);
free(arr);
arr[0] = 5;  // Noncompliant: accessing freed memory

compliant:
char* ptr = malloc(100);
strcpy(ptr, "data");
free(ptr);
ptr = NULL;  // Compliant: use before free, then nullify

int* arr = malloc(sizeof(int) * 10);
arr[0] = 5;
free(arr);
arr = NULL;  // Compliant: proper usage order
